import { DATA_INDEX, TEMPLATE_MODAL_TYPE, TEMPLATE_STATUS_MAP, STATUS, HELP_DOC } from '../../utils/constants';
import { Card, Row, Col, Input, Modal, Button, Select, Image, Space } from 'antd';
import React, { useState } from 'react'
import { containerConstantsService } from '../../utils/containerconstants/ContainerConstants';
import StartScratchIcon from '../../images/create_template_icon.svg'
import { fetchAllPartyMaster, saveLabelTemplate } from "../APIConfig/LabelTemplateAction";
import { toUpper } from 'lodash';
import { notifyResponseMessage } from '../commoncomponent/NotificationComponent/notifyResponseMessage';

const containerConstants = containerConstantsService.getInstance();
const { Option } = Select;

const CustomModal = ({ showModalDialog, showHelpModal, showConfirmModalDialog, ...otherProps }) => {

    const [formData, setFormData] = useState({});
    const [selectedDoc, setSelectedDoc] = useState('Get Reference Number of a process');
    const [previewTemplate, setPreviewTemplate] = useState(false);
    const [partyMasterCodeList, setPartyMasterCodeList] = useState([]);

    const handleClickOk = () => {
        if (showModalDialog) {
            onSaveLabelTemplate();
        }
        else if (showConfirmModalDialog.visible) {
            if (showConfirmModalDialog.rowId) {
                otherProps.deleteTemplate(showConfirmModalDialog.rowId);
            } else {
                otherProps.updateTemplateStatus(showConfirmModalDialog.record);
            }
            handleClickCancel();
        }
    }

    const handleClickCancel = () => {
        showModalDialog && otherProps.setShowModalDialog(false)
        showHelpModal && otherProps.setShowHelpModal(false)
        showConfirmModalDialog && otherProps.setShowConfirmModalDialog({ visible: false, okText: '', title: '' })
        setFormData({});
    }

    const getAllPartyMaster = () => {
        fetchAllPartyMaster()
            .then(response => {
                if (response && response.status === 200) {
                    const partyMasterList = response.data?.data;
                    const merchantCodeList = partyMasterList.map(partyMaster => partyMaster?.merchantCode)
                    setPartyMasterCodeList(merchantCodeList);
                }
            })
            .catch(error => {

            });
    }

    const onSaveLabelTemplate = () => {
        saveLabelTemplate({ ...formData, [DATA_INDEX.TEMPLATE_STATUS]: TEMPLATE_STATUS_MAP.DRAFT })
            .then(response => {
                if (response && response.status === 200) {
                    if (toUpper(response.data?.status) === STATUS.SUCCESS) {
                        notifyResponseMessage(STATUS.SUCCESS, response?.data?.message);

                        otherProps.setShowEditor({
                            visible: true,
                            [DATA_INDEX.TEMPLATE_ID]: response.data?.data?.id,
                            [DATA_INDEX.TEMPLATE_STATUS]: response.data?.data?.status,
                            [DATA_INDEX.TEMPLATE_NAME]: response.data?.data?.name,
                            [DATA_INDEX.TEMPLATE_SCRIPT]: '',
                        });
                        handleClickCancel();
                    }else{
                        notifyResponseMessage(STATUS.ERROR, response?.data?.message);

                    }
                }
            })
            .catch(error => {

            });
    }

    const updateFieldValue = (e, name) => {
        setFormData({ ...formData, [name]: e.target.value });
    }

    const getRowWithSelectElementJsx = (label, name, options, spanSize) => {
        return (
            <Row>
                <Col span={spanSize[0]}>{label}</Col>
                <Col span={spanSize[1]}>
                    <Select onChange={value => { !(name === DATA_INDEX.ELEMENT_OPTIONS) ? setFormData({ ...formData, [name]: value }) : setSelectedDoc(value) }}
                        placeholder={containerConstants.formatString(containerConstants.SELECT)}
                        value={!(name === DATA_INDEX.ELEMENT_OPTIONS) ? formData[name] : selectedDoc}
                        onFocus={name === DATA_INDEX.PARTY_CODE && getAllPartyMaster}
                    >
                        {options.map(option => option.key ? <Option value={option.key}>{option.value}</Option> : <Option value={option}>{option}</Option> )}
                    </Select>
                </Col>
            </Row>
        );
    }

    const getRowWithInputElementJsx = (label, name, disabled) => {
        return (
            <Row>
                <Col span={7}>{label}</Col>
                <Col span={17}>
                    <Input name={name} value={formData[name]} placeholder={containerConstants.formatString(containerConstants.PLACEHOLDER)} disabled={disabled} onChange={(e) => updateFieldValue(e, name)} />
                </Col>
            </Row>
        );
    }

    const getPreviewTemplateJSX = () => {
        return (
            <div className='available-template'>
                <Image
                    src={''}
                    preview={{
                        visible: false,
                        src: '',
                        mask:
                            <div>
                                <Space direction='vertical' size={12}>
                                    <Button size='small' ghost onClick={() => setPreviewTemplate(true)}>
                                        {containerConstants.formatString(containerConstants.PREVIEW)}
                                    </Button>
                                    <Button size='small' type='primary' style={{ color: '#FFFFFF', width: '65px' }}>
                                        {containerConstants.formatString(containerConstants.IMPORT)}
                                    </Button>
                                </Space>
                            </div>,
                        maskClassName: 'available-template-hover',
                    }}
                    placeholder={true}
                />
            </div>
        );
    }

    const modalWidth = () => showModalDialog ? (showModalDialog.modalType === TEMPLATE_MODAL_TYPE.CHOOSE_TEMPLATE ? 'fit-content' : '32%') : (showConfirmModalDialog && showConfirmModalDialog.visible) ? '32%' : '51.2%';

    return (
        <div>
            <Modal
                title={(showModalDialog && showModalDialog.title) || (showHelpModal && showHelpModal.title) || (showConfirmModalDialog && showConfirmModalDialog.title)}
                visible={(showModalDialog && showModalDialog.visible) || (showHelpModal && showHelpModal.visible) || (showConfirmModalDialog && showConfirmModalDialog.visible)}
                closable={((showModalDialog && showModalDialog.modalType) === TEMPLATE_MODAL_TYPE.CREATE_TEMPLATE && showConfirmModalDialog.visible) ? false : true}
                className={(showModalDialog && showModalDialog.visible) ? 'template-form-modal ' : (showConfirmModalDialog && showConfirmModalDialog.visible) ? 'template-delete-modal' : 'template-help-modal'}
                headStyle={{ fontSize: '18px' }}
                bodyStyle={{ padding: (showModalDialog && (showModalDialog.modalType === TEMPLATE_MODAL_TYPE.CHOOSE_TEMPLATE)) ? '0 18px 0 24px' : '0 24px' }}
                width={modalWidth()}
                onCancel={handleClickCancel}
                footer={
                    ((showModalDialog && showModalDialog.visible && showModalDialog.modalType === TEMPLATE_MODAL_TYPE.CREATE_TEMPLATE) || (showConfirmModalDialog && showConfirmModalDialog.visible)) ? [
                        <Button style={{ color: '#727272', border: 0 }} onClick={handleClickCancel}>
                            {containerConstants.formatString(containerConstants.CANCEL)}
                        </Button>,
                        <Button type="primary" style={{ color: '#FFFFFF' }} onClick={handleClickOk}>
                            {(showModalDialog && showModalDialog.okText) || (showConfirmModalDialog && showConfirmModalDialog.okText)}
                        </Button>,
                    ] : null}
            >
                <Card className='fw500 fs12 lh18 border-none'
                    bodyStyle={{ color: '#727272', padding: (showModalDialog && (showModalDialog.modalType === TEMPLATE_MODAL_TYPE.CHOOSE_TEMPLATE)) ? '24px 0 0' : (showConfirmModalDialog && showConfirmModalDialog.visible) ? '0 0 24px' : '24px 0' }}
                >
                    {(showModalDialog && showModalDialog.modalType === TEMPLATE_MODAL_TYPE.CREATE_TEMPLATE) ?
                        <div>
                            {getRowWithInputElementJsx(containerConstants.formatString(containerConstants.NAME), DATA_INDEX.TEMPLATE_NAME, false)}
                            <br />
                            {getRowWithInputElementJsx(containerConstants.formatString(containerConstants.CODE), DATA_INDEX.TEMPLATE_CODE, false)}
                            <br />
                            {getRowWithSelectElementJsx(containerConstants.formatString(containerConstants.PAGE_SIZE), DATA_INDEX.PAGE_SIZE, [{value:"A4" ,key:"A4"}, {value:'4x6"',key:'4x6'}, {value:'6x4"',key:'6x4'}, {value:'2x3"',key:'2x3'}, {value:'4x2"',key:'4x2'}], [7, 17])}
                        </div> :
                        <div>
                            {(showModalDialog && showModalDialog.modalType === TEMPLATE_MODAL_TYPE.CHOOSE_TEMPLATE) ?
                                <div id='all-template-container' className='flex justify-center' style={{ flexWrap: 'wrap', width: '250px' }}>
                                    <div className='scratch-template pointer' onClick={() => {
                                        otherProps.setShowModalDialog({
                                            visible: true,
                                            title: containerConstants.formatString(containerConstants.CREATE_TEMPLATE),
                                            okText: containerConstants.formatString(containerConstants.DONE),
                                            modalType: TEMPLATE_MODAL_TYPE.CREATE_TEMPLATE

                                        })
                                    }}>
                                        <img alt='' src={StartScratchIcon} />
                                        <p className='fw400 fs12 lh18'>{containerConstants.formatString(containerConstants.START_SCRATCH)}</p>
                                    </div>
                                    {/* {temporaryTeplateList.map(() => getPreviewTemplateJSX())} */}
                                </div>
                                :
                                (showConfirmModalDialog && showConfirmModalDialog.visible) ?
                                    <p className="fw400 fs14 lh16 mt16" style={{ color: '#212121' }} >
                                        {showConfirmModalDialog.description}
                                    </p>
                                    :
                                    <div>
                                        {getRowWithSelectElementJsx(containerConstants.formatString(containerConstants.ELEMENT_OPTIONS), DATA_INDEX.ELEMENT_OPTIONS, Object.keys(HELP_DOC), [10, 14])}
                                        <br />
                                        <Card
                                            bordered={false}
                                            bodyStyle={{ background: '#F3F3F3', border: '1px solid #DADADA', borderRadius: '3px', padding: '12px', maxHeight: '164px', overflow: 'auto' }}
                                        >
                                            {HELP_DOC[selectedDoc] &&
                                                HELP_DOC[selectedDoc].map((doc, index) => {
                                                    return (
                                                        <div>
                                                            {(doc.note !== undefined) ?
                                                            (<div>
                                                                <div className='fw500 fs14 lh22'>{containerConstants.formatString(containerConstants.NOTE)}</div>
                                                                {doc.note.map(paragraphLine => <p className='fw400 fs12 lh18'>{paragraphLine}</p>)}
                                                            </div>) :
                                                            (<div>
                                                                <div className='fw500 fs14 lh22'>{containerConstants.formatString(containerConstants.SYNTAX)}</div>
                                                                {doc.syntax.map(paragraphLine => <p className='fw400 fs12 lh18'>{paragraphLine}</p>)}
                                                            </div>)
                                                            }
                                                            <br />
                                                            <div>
                                                                <div className='fw500 fs14 lh22'>{containerConstants.formatString(containerConstants.EXAMPLE)}</div>
                                                                {doc.example.map(paragraphLine => typeof paragraphLine === 'string' ? <p className='fw400 fs12 lh18'>{paragraphLine}</p> : paragraphLine)}
                                                            </div>
                                                            {(index < (HELP_DOC[selectedDoc].length - 1)) && <br />}
                                                        </div>
                                                    );
                                                })}
                                        </Card>
                                    </div>}
                        </div>}
                </Card>
            </Modal>
            <Modal
                title={containerConstants.formatString(containerConstants.PREVIEW)}
                visible={previewTemplate}
                className={'template-form-modal'}
                headStyle={{ fontSize: '18px' }}
                bodyStyle={{ padding: '24px 24px 36px' }}
                width={'768px'}
                onCancel={() => setPreviewTemplate(false)}
                footer={null}
            >
                <div className='flex justify-center'>
                    <div className='flex justify-center preview-template'>
                        <img alt='' src={''} />
                    </div>
                </div>
            </Modal>
        </div>
    )
}

export default CustomModal
